import os
import yaml
import json
import jsonschema
from datetime import datetime

class ConfigManager:
    """Configuration and state management"""

    def __init__(self, config_file, state_file):
        self.config_file = config_file
        self.state_file = state_file
        self.config = None
        self.state = None

        # Define config schema
        self.config_schema = {
            "type": "object",
            "properties": {
                "default_duration": {"type": "integer", "minimum": 1, "maximum": 86400},
                "urls": {
                    "type": "array",
                    "items": {
                        "type": "object",
                        "properties": {
                            "url": {"type": "string", "format": "uri"},
                            "duration": {"type": "integer", "minimum": 1, "maximum": 86400}
                        },
                        "required": ["url"]
                    }
                },
                "mqtt": {
                    "type": "object",
                    "properties": {
                        "broker": {"type": "string"},
                        "port": {"type": "integer"},
                        "username": {"type": ["string", "null"]},
                        "password": {"type": ["string", "null"]},
                        "client_id": {"type": "string"},
                        "topics": {
                            "type": "object",
                            "properties": {
                                "commands": {"type": "string"},
                                "status": {"type": "string"},
                                "config": {"type": "string"}
                            },
                            "required": ["commands", "status"]
                        }
                    },
                    "required": ["broker", "port", "client_id", "topics"]
                }
            },
            "required": ["default_duration", "urls", "mqtt"]
        }

        # Define default state
        self.default_state = {
            "current_index": 0,
            "is_paused": False,
            "rotation_start_time": datetime.utcnow().isoformat(),
            "total_rotations": 0,
            "error_count": 0,
            "last_config_update": datetime.utcnow().isoformat(),
            "device_info": {
                "hostname": os.uname().nodename,
                "version": "1.0.0",
                "chromium_version": "" # Will be populated later
            }
        }

    def load_config(self):
        """Load configuration from YAML file"""
        try:
            with open(self.config_file, 'r') as f:
                config = yaml.safe_load(f)

            # Validate config against schema
            self.validate_config(config)
            self.config = config

            # Update state with config load time
            self.update_state({"last_config_update": datetime.utcnow().isoformat()})

            return self.config
        except (yaml.YAMLError, jsonschema.exceptions.ValidationError) as e:
            raise ValueError(f"Invalid configuration: {str(e)}")
        except FileNotFoundError:
            # Create default config if file doesn't exist
            default_config = {
                "default_duration": 30,
                "urls": [
                    {"url": "https://example.com", "duration": 30}
                ],
                "mqtt": {
                    "broker": "localhost",
                    "port": 1883,
                    "username": None,
                    "password": None,
                    "client_id": "web_rotator_001",
                    "topics": {
                        "commands": "displays/commands",
                        "status": "displays/status",
                        "config": "displays/config"
                    }
                }
            }
            self.save_config(default_config)
            self.config = default_config
            return default_config

    def save_config(self, config):
        """Save configuration to YAML file"""
        # Validate before saving
        self.validate_config(config)

        # Create directory if it doesn't exist
        os.makedirs(os.path.dirname(self.config_file), exist_ok=True)

        with open(self.config_file, 'w') as f:
            yaml.dump(config, f, default_flow_style=False)

        self.config = config
        self.update_state({"last_config_update": datetime.utcnow().isoformat()})
        return True

    def validate_config(self, config):
        """Validate configuration against schema"""
        jsonschema.validate(instance=config, schema=self.config_schema)
        return True

    def get_state(self):
        """Get current state, loading from file if necessary"""
        if self.state is None:
            try:
                with open(self.state_file, 'r') as f:
                    self.state = json.load(f)
            except (FileNotFoundError, json.JSONDecodeError):
                # Initialize with default state
                self.state = self.default_state.copy()
                self._save_state()

        return self.state

    def update_state(self, state_update):
        """Update state with new values and persist"""
        current_state = self.get_state()
        current_state.update(state_update)
        self.state = current_state
        return self._save_state()

    def _save_state(self):
        """Save state to JSON file"""
        # Create directory if it doesn't exist
        os.makedirs(os.path.dirname(self.state_file), exist_ok=True)

        with open(self.state_file, 'w') as f:
            json.dump(self.state, f, indent=2)

        return True
