import os
import json
from flask import Blueprint, jsonify, request, current_app
from app.models.config import ConfigManager
from app.services.display_manager import DisplayManager

bp = Blueprint('api', __name__, url_prefix='/api')

# Get references to global services
def get_config_manager():
    if 'config_manager' not in current_app.config:
        config_file = current_app.config.get('CONFIG_FILE')
        state_file = current_app.config.get('STATE_FILE')
        current_app.config['config_manager'] = ConfigManager(config_file, state_file)
    return current_app.config['config_manager']

def get_display_manager():
    if 'display_manager' not in current_app.config:
        return None
    return current_app.config['display_manager']

# Configuration Management Endpoints
@bp.route('/config', methods=['GET'])
def get_config():
    """Get current configuration"""
    config_manager = get_config_manager()
    return jsonify(config_manager.config)

@bp.route('/config', methods=['PUT'])
def update_config():
    """Update configuration"""
    config_manager = get_config_manager()
    display_manager = get_display_manager()

    if not request.is_json:
        return jsonify({'error': 'Request must be JSON'}), 400

    try:
        new_config = request.get_json()
        config_manager.validate_config(new_config)
        config_manager.save_config(new_config)

        # Reload display manager if available
        if display_manager:
            display_manager.reload_config()

        return jsonify({'success': True, 'message': 'Configuration updated'})
    except Exception as e:
        return jsonify({'error': str(e)}), 400

@bp.route('/config/reload', methods=['POST'])
def reload_config():
    """Reload configuration from file"""
    config_manager = get_config_manager()
    display_manager = get_display_manager()

    try:
        config_manager.load_config()

        # Reload display manager if available
        if display_manager:
            display_manager.reload_config()

        return jsonify({'success': True, 'message': 'Configuration reloaded'})
    except Exception as e:
        return jsonify({'error': str(e)}), 500

# Display Control Endpoints
@bp.route('/status', methods=['GET'])
def get_status():
    """Get current display status"""
    display_manager = get_display_manager()

    if not display_manager:
        return jsonify({'error': 'Display manager not initialized'}), 503

    status = display_manager.get_status()
    return jsonify(status)

@bp.route('/control/pause', methods=['POST'])
def pause_rotation():
    """Pause rotation"""
    display_manager = get_display_manager()

    if not display_manager:
        return jsonify({'error': 'Display manager not initialized'}), 503

    result = display_manager.pause_rotation()
    return jsonify({'success': result, 'message': 'Rotation paused'})

@bp.route('/control/resume', methods=['POST'])
def resume_rotation():
    """Resume rotation"""
    display_manager = get_display_manager()

    if not display_manager:
        return jsonify({'error': 'Display manager not initialized'}), 503

    result = display_manager.resume_rotation()
    return jsonify({'success': result, 'message': 'Rotation resumed'})

@bp.route('/control/jump/<int:index>', methods=['POST'])
def jump_to_url(index):
    """Jump to URL at index"""
    display_manager = get_display_manager()

    if not display_manager:
        return jsonify({'error': 'Display manager not initialized'}), 503

    result = display_manager.jump_to_url(index)

    if result:
        return jsonify({'success': True, 'message': f'Jumped to URL at index {index}'})
    else:
        return jsonify({'error': f'Failed to jump to URL at index {index}'}), 400

@bp.route('/control/next', methods=['POST'])
def next_url():
    """Skip to next URL"""
    display_manager = get_display_manager()

    if not display_manager:
        return jsonify({'error': 'Display manager not initialized'}), 503

    result = display_manager.next_url()

    if result:
        return jsonify({'success': True, 'message': 'Moved to next URL'})
    else:
        return jsonify({'error': 'Failed to move to next URL'}), 400

# URL Management Endpoints
@bp.route('/urls', methods=['GET'])
def get_urls():
    """List all URLs"""
    config_manager = get_config_manager()
    urls = config_manager.config.get('urls', [])
    return jsonify(urls)

@bp.route('/urls', methods=['POST'])
def add_url():
    """Add new URL"""
    display_manager = get_display_manager()

    if not display_manager:
        return jsonify({'error': 'Display manager not initialized'}), 503

    if not request.is_json:
        return jsonify({'error': 'Request must be JSON'}), 400

    try:
        url_config = request.get_json()
        index = request.args.get('index', None)

        if index is not None:
            try:
                index = int(index)
            except ValueError:
                return jsonify({'error': 'Index must be an integer'}), 400

        result = display_manager.add_url(url_config, index)

        if result:
            return jsonify({'success': True, 'message': 'URL added'}), 201
        else:
            return jsonify({'error': 'Failed to add URL'}), 400
    except Exception as e:
        return jsonify({'error': str(e)}), 400

@bp.route('/urls/<int:index>', methods=['PUT'])
def update_url(index):
    """Update URL at index"""
    config_manager = get_config_manager()
    display_manager = get_display_manager()

    if not display_manager:
        return jsonify({'error': 'Display manager not initialized'}), 503

    if not request.is_json:
        return jsonify({'error': 'Request must be JSON'}), 400

    try:
        # Get current URLs
        config = config_manager.config
        urls = config.get('urls', [])

        # Validate index
        if index < 0 or index >= len(urls):
            return jsonify({'error': f'Invalid URL index: {index}'}), 404

        # Update URL
        url_config = request.get_json()
        urls[index] = url_config

        # Save updated config
        config['urls'] = urls
        config_manager.save_config(config)

        # Reload display manager
        display_manager.reload_config()

        return jsonify({'success': True, 'message': f'URL at index {index} updated'})
    except Exception as e:
        return jsonify({'error': str(e)}), 400

@bp.route('/urls/<int:index>', methods=['DELETE'])
def delete_url(index):
    """Remove URL at index"""
    display_manager = get_display_manager()

    if not display_manager:
        return jsonify({'error': 'Display manager not initialized'}), 503

    result = display_manager.remove_url(index)

    if result:
        return jsonify({'success': True, 'message': f'URL at index {index} removed'})
    else:
        return jsonify({'error': f'Failed to remove URL at index {index}'}), 404

# System Management Endpoints
@bp.route('/health', methods=['GET'])
def health_check():
    """Health check endpoint"""
    display_manager = get_display_manager()
    config_manager = get_config_manager()

    health = {
        'status': 'ok',
        'version': '1.0.0',
        'config_loaded': config_manager.config is not None,
        'display_manager': display_manager is not None
    }

    # Add more detailed status if display manager is available
    if display_manager:
        status = display_manager.get_status()
        health['display_status'] = status.get('status')
        health['urls_configured'] = status.get('total_urls', 0)

    return jsonify(health)

@bp.route('/system/restart', methods=['POST'])
def restart_system():
    """Restart display system"""
    display_manager = get_display_manager()

    if not display_manager:
        return jsonify({'error': 'Display manager not initialized'}), 503

    try:
        # Shutdown current display manager
        display_manager.shutdown()

        # Get browser manager and MQTT client
        browser_manager = current_app.config.get('browser_manager')
        mqtt_client = current_app.config.get('mqtt_client')

        # Shutdown browser
        if browser_manager:
            browser_manager.shutdown()

        # Reinitialize browser
        if browser_manager:
            browser_manager.initialize()

        # Restart display manager
        display_manager.start_rotation()

        return jsonify({'success': True, 'message': 'Display system restarted'})
    except Exception as e:
        return jsonify({'error': f'Failed to restart system: {str(e)}'}), 500
